package com.infy.inventrack.catalog.service;
import com.infy.inventrack.catalog.entity.*; import com.infy.inventrack.catalog.mapper.CatalogMapper; import com.infy.inventrack.catalog.repository.*; import com.infy.inventrack.common.constants.InfyInvenTrackConstants; import com.infy.inventrack.common.dto.*; import com.infy.inventrack.common.exception.*; import org.springframework.cache.annotation.*; import org.springframework.security.access.prepost.PreAuthorize; import org.springframework.stereotype.Service; import org.springframework.transaction.annotation.Transactional; import java.math.BigDecimal; import java.util.*; import java.util.function.Predicate;
@Service public class ProductService { private final ProductRepository products; private final CategoryRepository categories; public ProductService(ProductRepository p, CategoryRepository c){products=p;categories=c;} @Transactional @PreAuthorize("hasRole('ADMIN')") public String createProduct(ProductRequest r){ if(products.existsBySku(r.getSku().trim())) throw new DuplicateResourceException(InfyInvenTrackConstants.DUPLICATE_SKU.value()); products.save(copy(r,new Product())); return InfyInvenTrackConstants.PRODUCT_CREATED.value(); } @Transactional(readOnly=true) @Cacheable(value="productsBySku",key="#sku") @PreAuthorize("hasAnyRole('ADMIN','CUSTOMER')") public ProductResponse getProductBySku(String sku){ return CatalogMapper.toProductResponse(find(sku)); } @Transactional @CacheEvict(value="productsBySku",key="#sku") @PreAuthorize("hasRole('ADMIN')") public String updateProduct(String sku, ProductRequest r){ products.save(copy(r,find(sku))); return InfyInvenTrackConstants.PRODUCT_UPDATED.value(); } @Transactional @CacheEvict(value="productsBySku",key="#sku") @PreAuthorize("hasRole('ADMIN')") public String deleteProduct(String sku){ products.delete(find(sku)); return InfyInvenTrackConstants.PRODUCT_DELETED.value(); } @Transactional(readOnly=true) @PreAuthorize("hasAnyRole('ADMIN','CUSTOMER')") public List<ProductResponse> searchProducts(String name,String category,BigDecimal minPrice,BigDecimal maxPrice,int page,int size,String sortBy){ validateSearch(name,category,minPrice,maxPrice,page,size,sortBy); Predicate<Product> f=p->true; if(name!=null) f=f.and(p->p.getProductName().toLowerCase().contains(name.trim().toLowerCase())); if(category!=null) f=f.and(p->p.getCategory().getName().equalsIgnoreCase(category.trim())); if(minPrice!=null) f=f.and(p->p.getPrice().compareTo(minPrice)>=0); if(maxPrice!=null) f=f.and(p->p.getPrice().compareTo(maxPrice)<=0); return products.findAll().stream().filter(f).sorted(comp(sortBy)).skip((long)page*size).limit(size).map(CatalogMapper::toProductResponse).toList(); } @Transactional(readOnly=true) @PreAuthorize("hasAnyRole('ADMIN','CUSTOMER')") public List<ProductResponse> findTopNExpensiveProducts(Integer n){ if(n==null||n<=0) throw invalid("n"); return products.findAll().stream().sorted(Comparator.comparing(Product::getPrice).reversed()).limit(n).map(CatalogMapper::toProductResponse).toList(); } @Transactional @CacheEvict(value="productsBySku",key="#sku") @PreAuthorize("hasRole('ADMIN')") public ProductResponse updateDescription(String sku,DescriptionUpdateRequest r){ Product p=find(sku); p.setDescription(r.getDescription().trim()); return CatalogMapper.toProductResponse(products.save(p)); } private Product copy(ProductRequest r,Product p){ Category c=categories.findByNameIgnoreCase(r.getCategory().trim()).orElseThrow(()->new ResourceNotFoundException(InfyInvenTrackConstants.CATEGORY_NOT_FOUND.value())); p.setProductName(r.getProductName().trim()); p.setSku(r.getSku().trim()); p.setPrice(r.getPrice()); p.setImageUrl(r.getImageUrl().trim()); p.setCategory(c); p.setDescription(r.getDescription()); p.setBrand(r.getBrand().trim()); p.setStockQuantity(r.getStockQuantity()); return p; } private Product find(String sku){ if(sku==null||sku.isBlank()) throw invalid("sku"); return products.findBySku(sku.trim()).orElseThrow(()->new ResourceNotFoundException(InfyInvenTrackConstants.PRODUCT_NOT_FOUND.value())); } private Comparator<Product> comp(String s){ if("price".equalsIgnoreCase(s)) return Comparator.comparing(Product::getPrice); if("name".equalsIgnoreCase(s)) return Comparator.comparing(Product::getProductName,String.CASE_INSENSITIVE_ORDER); return Comparator.comparing((Product p)->p.getCategory().getName(),String.CASE_INSENSITIVE_ORDER).thenComparing(Product::getProductName,String.CASE_INSENSITIVE_ORDER); } private void validateSearch(String name,String category,BigDecimal minPrice,BigDecimal maxPrice,int page,int size,String sortBy){ if(name!=null&&name.isBlank()) throw invalid("name"); if(category!=null&&category.isBlank()) throw invalid("category"); if(minPrice!=null&&minPrice.compareTo(BigDecimal.ZERO)<0) throw invalid("minPrice"); if(maxPrice!=null&&maxPrice.compareTo(BigDecimal.ZERO)<0) throw invalid("maxPrice"); if(page<0) throw invalid("page"); if(size<=0) throw invalid("size"); if(sortBy==null||!(sortBy.equalsIgnoreCase("category")||sortBy.equalsIgnoreCase("price")||sortBy.equalsIgnoreCase("name"))) throw invalid("sortBy"); } private BusinessValidationException invalid(String a){ return new BusinessValidationException(String.format(InfyInvenTrackConstants.INVALID_ATTRIBUTE.value(),a)); } }
